const files = $json.files || [];
const taskDesc = $json.task?.description || $json.description || '';
const projectGoal = $json.project_goal || '';
const code = files.map(f => `### ${f.path}
\`\`\`
${f.content}
\`\`\``).join('

');
const context = (projectGoal || taskDesc) ? `

Project Goal: ${projectGoal}
Current Task: ${taskDesc}
` : '';
return [{
  json: {
    model: $env.REVIEWER_MODEL || 'qwen/qwen3.5-9b',
    messages: [{
      role: 'user',
      content: `You are a Senior Code Reviewer. Evaluate this code for BOTH security and quality.${context}

Code:
${code}

Return ONLY valid JSON (no markdown, no explanation):
{"quality_score":number,"job_complete":boolean,"security_issues":[{"severity":"critical|high|medium","issue":"...","fix":"..."}],"quality_improvements":[{"area":"...","fix":"..."}]}

RULES:
- quality_score: overall code quality 0-100
- job_complete: true ONLY if ALL requirements from the task are fully implemented
- security_issues: OWASP Top 10 vulnerabilities. Empty array if none found.
- quality_improvements: specific actionable fixes. Empty array if code is good.
- Do NOT flag style preferences, only real bugs and security issues.`
    }],
    temperature: 0.3,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 4096
  }
}];

const raw = $json.choices[0].message.content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
const jsonMatch = content.match(/\{[\s\S]*\}/);
let review;
try { review = JSON.parse(jsonMatch ? jsonMatch[0] : content); } catch (e) { review = { raw_output: content }; }
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { review, files: trigger.files, task: trigger.task, project_goal: trigger.project_goal } }];
